import torch
from piq import psnr, ssim

def evaluate_results(result_dict, forward_op):
    metric_list = {
        'psnr': lambda x, y: psnr(x.clip(0, 1), y.clip(0, 1), data_range=1.0, reduction='none'),
        'ssim': lambda x, y: ssim(x.clip(0, 1), y.clip(0, 1), data_range=1.0, reduction='none')
    }

    pred = result_dict['recon']
    target = result_dict['target']

    metric_dict = {}
    for metric_name, metric_func in metric_list.items():
        if pred.shape != target.shape:
            val = metric_func(pred, target.repeat(pred.shape[0], 1, 1, 1)).mean().item()
        else:
            val = metric_func(pred, target).mean().item()
        metric_dict[metric_name] = val

    return metric_dict

# Example usage
result_dict = {
    'recon': torch.rand(1, 3, 256, 256),  # Example predicted tensor
    'target': torch.rand(1, 3, 256, 256)  # Example ground truth tensor
}

metrics = evaluate_results(result_dict, None)
